{
  "name": "Hotel Statement Analyzer AI",
  "description": "An intelligent dashboard to analyze hotel PDF statements, clean transaction data, and categorize expenses using Gemini 2.5."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Currency {
  MXN = 'MXN',
  USD = 'USD'
}

export enum Language {
  ES = 'ES',
  EN = 'EN'
}

export enum Category {
  FOOD = 'Alimentos/Food',
  BEVERAGE = 'Bebidas/Beverage',
  ROOM = 'Habitación/Room',
  TAX = 'Impuestos/Tax',
  DISCOUNT = 'Descuento/Discount',
  SERVICE = 'Servicio/Service',
  OTHER = 'Otros/Other'
}

export interface Transaction {
  date: string;
  originalDescription: string;
  cleanName: string;
  amount: number;
  currency: string;
  category: Category;
}

export interface AnalysisResult {
  hotelName: string;
  period: string;
  transactions: Transaction[];
  totalAmount: number;
  detectedCurrency: string;
}

export interface Translation {
  title: string;
  uploadPrompt: string;
  uploadButton: string;
  analyzing: string;
  totalSpend: string;
  transactions: string;
  categoryDistribution: string;
  date: string;
  description: string;
  amount: string;
  category: string;
  cleanName: string;
  errorGeneric: string;
  reset: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AnalysisResult, Category } from "../types";

const parsePdf = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      // Remove Data-URL declaration (e.g., data:application/pdf;base64,)
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const analyzeStatement = async (file: File): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is missing.");
  }

  const base64Data = await parsePdf(file);
  const ai = new GoogleGenAI({ apiKey });

  // Define the schema for structured output
  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      hotelName: { type: Type.STRING, description: "Name of the hotel found in the header" },
      period: { type: Type.STRING, description: "Billing period or statement date" },
      detectedCurrency: { type: Type.STRING, description: "Currency symbol or code detected (MXN, USD, $)" },
      transactions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            date: { type: Type.STRING },
            originalDescription: { type: Type.STRING },
            cleanName: { 
              type: Type.STRING, 
              description: "Simplified commercial name. Remove dates, transaction codes, room numbers. E.g., 'REST EL PATIO 23423' -> 'El Patio'" 
            },
            amount: { type: Type.NUMBER },
            category: { 
              type: Type.STRING, 
              enum: Object.values(Category),
              description: "Categorize based on description. 'Dersan' or 'ISH' are Impuestos/Tax." 
            },
            currency: { type: Type.STRING }
          },
          required: ["date", "originalDescription", "cleanName", "amount", "category"]
        }
      },
      totalAmount: { type: Type.NUMBER }
    },
    required: ["hotelName", "transactions", "totalAmount"]
  };

  const systemInstruction = `
    You are an expert financial analyst for hotel operations. 
    Your task is to extract transaction data from a hotel account statement PDF.

    CRITICAL RULES:
    1. Extract the Date, Description, and Amount for each line item in the main table.
    2. 'cleanName': Clean the description. Remove timestamps, check numbers, strange codes. Keep only the human-readable business/service name.
    3. 'category': Categorize strictly into: 
       - Alimentos/Food (Restaurants, Breakfast, Dinner)
       - Bebidas/Beverage (Bar, Lobby Bar, Minibar)
       - Habitación/Room (Room charge, Upgrades)
       - Impuestos/Tax (Look specifically for 'Dersan', 'ISH', 'IVA', 'TUA')
       - Descuento/Discount (Negative values, Credits)
       - Servicio/Service (Tips, Laundry, Spa)
       - Otros/Other (Anything else)
    4. Handle negative numbers correctly for the 'amount' field (make sure discounts are negative).
    5. Detect the currency of the document.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data
            }
          },
          {
            text: "Analyze this hotel statement PDF and extract the data according to the JSON schema."
          }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response from AI");
    }

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React from 'react';
import { Currency, Language } from '../types';
import { Globe, DollarSign } from 'lucide-react';

interface Props {
  language: Language;
  setLanguage: (l: Language) => void;
  currency: Currency;
  setCurrency: (c: Currency) => void;
}

export const LanguageCurrencyToggle: React.FC<Props> = ({ 
  language, 
  setLanguage, 
  currency, 
  setCurrency 
}) => {
  return (
    <div className="flex space-x-4 bg-white p-2 rounded-lg shadow-sm border border-gray-200">
      <button
        onClick={() => setLanguage(language === Language.ES ? Language.EN : Language.ES)}
        className="flex items-center space-x-1 px-3 py-1 rounded-md hover:bg-gray-100 transition-colors text-sm font-medium text-gray-700"
      >
        <Globe size={16} />
        <span>{language}</span>
      </button>

      <div className="w-px bg-gray-300 mx-2 h-6 self-center"></div>

      <button
        onClick={() => setCurrency(currency === Currency.MXN ? Currency.USD : Currency.MXN)}
        className="flex items-center space-x-1 px-3 py-1 rounded-md hover:bg-gray-100 transition-colors text-sm font-medium text-gray-700"
      >
        <DollarSign size={16} />
        <span>{currency}</span>
      </button>
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { AnalysisResult, Currency, Language, Transaction, Category } from '../types';
import { TRANSLATIONS, EXCHANGE_RATE_MXN_TO_USD, EXCHANGE_RATE_USD_TO_MXN } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Search, ArrowUpDown, Filter } from 'lucide-react';

interface Props {
  data: AnalysisResult;
  language: Language;
  currency: Currency;
  onReset: () => void;
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8', '#82ca9d', '#ffc658'];

export const Dashboard: React.FC<Props> = ({ data, language, currency, onReset }) => {
  const t = TRANSLATIONS[language];
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('All');

  // Helper to convert amounts based on selected currency preference vs detected currency
  const convert = (amount: number) => {
    // If detected is MXN and user wants USD
    if (data.detectedCurrency.includes('MXN') && currency === Currency.USD) {
      return amount * EXCHANGE_RATE_MXN_TO_USD;
    }
    // If detected is USD and user wants MXN
    if (data.detectedCurrency.includes('USD') && currency === Currency.MXN) {
      return amount * EXCHANGE_RATE_USD_TO_MXN;
    }
    // Same currency or undefined detected, return as is (assuming 1:1 for display if unknown)
    return amount;
  };

  const formattedTransactions = useMemo(() => {
    return data.transactions.map(tx => ({
      ...tx,
      convertedAmount: convert(tx.amount)
    })).filter(tx => {
      const matchesSearch = tx.cleanName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.originalDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || tx.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [data.transactions, currency, searchTerm, categoryFilter]);

  const totalSpend = formattedTransactions.reduce((acc, curr) => acc + curr.convertedAmount, 0);

  const chartData = useMemo(() => {
    const agg: Record<string, number> = {};
    formattedTransactions.forEach(tx => {
      // Don't include negative values (discounts) in the pie chart breakdown of spend
      if (tx.convertedAmount > 0) {
        agg[tx.category] = (agg[tx.category] || 0) + tx.convertedAmount;
      }
    });
    return Object.keys(agg).map(key => ({ name: key, value: agg[key] }));
  }, [formattedTransactions]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat(language === Language.ES ? 'es-MX' : 'en-US', {
      style: 'currency',
      currency: currency
    }).format(val);
  };

  return (
    <div className="w-full max-w-6xl mx-auto space-y-6">

      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">{data.hotelName}</h2>
          <p className="text-gray-500">{t.date}: {data.period}</p>
        </div>
        <div className="mt-4 md:mt-0 text-right">
          <p className="text-sm text-gray-500 uppercase tracking-wide">{t.totalSpend}</p>
          <p className="text-4xl font-extrabold text-blue-600">{formatCurrency(totalSpend)}</p>
        </div>
      </div>

      {/* Charts Area */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col items-center">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">{t.categoryDistribution}</h3>
          <div className="w-full h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">Top Expenses</h3>
          <div className="w-full h-64">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart data={chartData.sort((a,b) => b.value - a.value).slice(0,5)} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                  <Tooltip formatter={(value: number) => formatCurrency(value)} />
                  <Bar dataKey="value" fill="#3b82f6" radius={[0, 4, 4, 0]} />
               </BarChart>
             </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Transactions Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-200 flex flex-col sm:flex-row gap-4 justify-between items-center bg-gray-50">
          <h3 className="text-lg font-semibold">{t.transactions}</h3>

          <div className="flex gap-2 w-full sm:w-auto">
            <div className="relative flex-1 sm:w-64">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
              <input 
                type="text" 
                placeholder="Search..." 
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="relative">
               <select 
                  className="pl-3 pr-8 py-2 border border-gray-300 rounded-lg text-sm bg-white appearance-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer"
                  value={categoryFilter}
                  onChange={(e) => setCategoryFilter(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {Object.values(Category).map(cat => (
                   <option key={cat} value={cat}>{cat}</option>
                 ))}
               </select>
               <Filter className="absolute right-2 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" size={14} />
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
              <tr>
                <th className="px-6 py-3">{t.date}</th>
                <th className="px-6 py-3">{t.cleanName}</th>
                <th className="px-6 py-3 hidden md:table-cell">{t.description}</th>
                <th className="px-6 py-3">{t.category}</th>
                <th className="px-6 py-3 text-right">{t.amount}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {formattedTransactions.map((tx, idx) => (
                <tr key={idx} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-3 whitespace-nowrap text-gray-500">{tx.date}</td>
                  <td className="px-6 py-3 font-medium text-gray-900">{tx.cleanName}</td>
                  <td className="px-6 py-3 text-gray-400 text-xs hidden md:table-cell truncate max-w-xs">{tx.originalDescription}</td>
                  <td className="px-6 py-3">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium 
                      ${tx.category.includes('Impuestos') ? 'bg-red-100 text-red-800' : 
                        tx.category.includes('Alimentos') ? 'bg-green-100 text-green-800' :
                        tx.category.includes('Descuento') ? 'bg-yellow-100 text-yellow-800' :
                        'bg-gray-100 text-gray-800'}`}>
                      {tx.category.split('/')[language === Language.ES ? 0 : 1]}
                    </span>
                  </td>
                  <td className={`px-6 py-3 text-right font-medium ${tx.convertedAmount < 0 ? 'text-green-600' : 'text-gray-900'}`}>
                    {formatCurrency(tx.convertedAmount)}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {formattedTransactions.length === 0 && (
            <div className="p-8 text-center text-gray-500">
              No transactions found matching your filters.
            </div>
          )}
        </div>
      </div>

      <div className="flex justify-center pt-6 pb-12">
        <button 
          onClick={onReset}
          className="text-gray-500 hover:text-gray-800 underline text-sm transition-colors"
        >
          {t.reset}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AnalysisResult, Currency, Language } from './types';
import { TRANSLATIONS } from './constants';
import { analyzeStatement } from './services/geminiService';
import { LanguageCurrencyToggle } from './components/LanguageCurrencyToggle';
import { Dashboard } from './components/Dashboard';
import { Upload, FileText, Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>(Language.ES);
  const [currency, setCurrency] = useState<Currency>(Currency.MXN);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const t = TRANSLATIONS[language];

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      setError("Please select a PDF file.");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const result = await analyzeStatement(file);
      setData(result);
    } catch (err) {
      console.error(err);
      setError(t.errorGeneric);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setData(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-2 rounded-lg">
                <FileText className="text-white h-5 w-5" />
              </div>
              <span className="font-bold text-xl tracking-tight text-gray-800 hidden sm:block">
                {t.title}
              </span>
            </div>
            <LanguageCurrencyToggle 
              language={language} 
              setLanguage={setLanguage}
              currency={currency}
              setCurrency={setCurrency}
            />
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Error Notification */}
        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-md flex items-start">
            <AlertCircle className="text-red-500 mr-3 mt-0.5" size={20} />
            <div>
              <p className="text-sm text-red-700 font-medium">Error</p>
              <p className="text-sm text-red-600">{error}</p>
            </div>
          </div>
        )}

        {loading ? (
          // Loading State
          <div className="flex flex-col items-center justify-center h-[60vh]">
            <Loader2 className="h-12 w-12 text-blue-600 animate-spin mb-4" />
            <h3 className="text-xl font-semibold text-gray-700">{t.analyzing}</h3>
            <p className="text-gray-500 mt-2 max-w-md text-center">
              Gemini is extracting tables, cleaning descriptions, and categorizing expenses...
            </p>
          </div>
        ) : !data ? (
          // Empty State / Upload
          <div className="flex flex-col items-center justify-center h-[70vh]">
            <div className="w-full max-w-lg">
              <label 
                htmlFor="file-upload" 
                className="group relative flex flex-col items-center justify-center w-full h-64 border-2 border-gray-300 border-dashed rounded-2xl cursor-pointer bg-white hover:bg-gray-50 hover:border-blue-400 transition-all duration-200 shadow-sm"
              >
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <div className="p-4 bg-blue-50 rounded-full mb-4 group-hover:bg-blue-100 transition-colors">
                    <Upload className="w-8 h-8 text-blue-500" />
                  </div>
                  <p className="mb-2 text-lg text-gray-700 font-medium">{t.uploadPrompt}</p>
                  <p className="text-xs text-gray-400">PDF, max 10MB</p>
                </div>
                <input 
                  id="file-upload" 
                  type="file" 
                  accept="application/pdf"
                  className="hidden" 
                  onChange={handleFileUpload}
                />
              </label>
              <div className="mt-8 grid grid-cols-1 sm:grid-cols-3 gap-4 text-center">
                <div className="p-4 bg-white rounded-lg shadow-sm border border-gray-100">
                  <p className="font-semibold text-blue-600">1. Extract</p>
                  <p className="text-xs text-gray-500 mt-1">AI reads tables from PDF</p>
                </div>
                <div className="p-4 bg-white rounded-lg shadow-sm border border-gray-100">
                  <p className="font-semibold text-blue-600">2. Clean</p>
                  <p className="text-xs text-gray-500 mt-1">Normalizes merchant names</p>
                </div>
                <div className="p-4 bg-white rounded-lg shadow-sm border border-gray-100">
                  <p className="font-semibold text-blue-600">3. Categorize</p>
                  <p className="text-xs text-gray-500 mt-1">Groups by spending type</p>
                </div>
              </div>
            </div>
          </div>
        ) : (
          // Dashboard View
          <Dashboard 
            data={data} 
            language={language} 
            currency={currency} 
            onReset={handleReset}
          />
        )}
      </main>
    </div>
  );
};

export default App;

