import { Search, ArrowUpDown, Filter } from 'lucide-react';

interface Props {
  data: AnalysisResult;
  language: Language;
  currency: Currency;
  onReset: () => void;
}

// Define specific colors for each category to ensure consistency across charts and table
const CATEGORY_COLORS: Record<string, string> = {
  [Category.FOOD]: '#00C49F', // Green
  [Category.BEVERAGE]: '#0088FE', // Blue
  [Category.ROOM]: '#8884d8', // Purple
  [Category.TAX]: '#FF8042', // Orange
  [Category.DISCOUNT]: '#FFBB28', // Yellow
  [Category.SERVICE]: '#82ca9d', // Light Green
  [Category.OTHER]: '#ffc658', // Light Orange
};

const DEFAULT_COLOR = '#9CA3AF'; // Gray

export const Dashboard: React.FC<Props> = ({ data, language, currency, onReset }) => {
  const t = TRANSLATIONS[language];
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('All');

  // Helper to convert amounts based on selected currency preference vs detected currency
  const convert = (amount: number) => {
    // If detected is MXN and user wants USD
    if (data.detectedCurrency.includes('MXN') && currency === Currency.USD) {
      return amount * EXCHANGE_RATE_MXN_TO_USD;
    }
    // If detected is USD and user wants MXN
    if (data.detectedCurrency.includes('USD') && currency === Currency.MXN) {
      return amount * EXCHANGE_RATE_USD_TO_MXN;
    }
    // Same currency or undefined detected, return as is (assuming 1:1 for display if unknown)
    return amount;
  };

  const formattedTransactions = useMemo(() => {
    return data.transactions.map(tx => ({
      ...tx,
      convertedAmount: convert(tx.amount)
    })).filter(tx => {
      const matchesSearch = tx.cleanName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.originalDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || tx.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [data.transactions, currency, searchTerm, categoryFilter]);

  const totalSpend = formattedTransactions.reduce((acc, curr) => acc + curr.convertedAmount, 0);

  const chartData = useMemo(() => {
    const agg: Record<string, number> = {};

    data.transactions.forEach(tx => {
        // We use Math.abs here so that Discounts (which are negative) appear in the charts
        // as a magnitude of value, allowing the user to see how much was discounted vs spent.
        const amt = Math.abs(convert(tx.amount));

        // We accumulate all values (even 0 usually doesn't happen, but good to be safe)
        // This ensures Discounts are included in the Pie/Bar charts.
        if (amt !== 0) {
            agg[tx.category] = (agg[tx.category] || 0) + amt;
        }
    });
    return Object.keys(agg).map(key => ({ name: key, value: agg[key] }));
  }, [data.transactions, currency]);

  // Clone and sort for BarChart to avoid mutating the memoized chartData array
  const topExpenses = useMemo(() => {
    return [...chartData].sort((a, b) => b.value - a.value).slice(0, 5);
  }, [chartData]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat(language === Language.ES ? 'es-MX' : 'en-US', {
      style: 'currency',
      currency: currency
    }).format(val);
  };

  const handleChartClick = (data: any) => {
    if (data && data.name) {
      // Toggle: if clicking the same category, reset to All
      setCategoryFilter(prev => prev === data.name ? 'All' : data.name);
    }
  };

  return (
    <div className="w-full max-w-6xl mx-auto space-y-6">

      {/* Header Info - Updated Layout */}
