import React, { useMemo, useState } from 'react';
import { AnalysisResult, Currency, Language, Transaction, Category } from '../types';
import { TRANSLATIONS, EXCHANGE_RATE_MXN_TO_USD, EXCHANGE_RATE_USD_TO_MXN } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Search, ArrowUpDown, Filter } from 'lucide-react';

interface Props {
  data: AnalysisResult;
  language: Language;
  currency: Currency;
  onReset: () => void;
}

// Define specific colors for each category to ensure consistency across charts and table
const CATEGORY_COLORS: Record<string, string> = {
  [Category.FOOD_AND_BEVERAGE]: '#3B82F6', // Blue (Standard Expense)
  [Category.ROOM]: '#8B5CF6', // Violet
  [Category.TAX]: '#F97316', // Orange
  [Category.DISCOUNT]: '#10B981', // Emerald Green (Distinct for Credit/Savings)
  [Category.SERVICE]: '#06B6D4', // Cyan
  [Category.OTHER]: '#94A3B8', // Slate
};

const DEFAULT_COLOR = '#9CA3AF'; // Gray

export const Dashboard: React.FC<Props> = ({ data, language, currency, onReset }) => {
  const t = TRANSLATIONS[language];
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('All');

  // Helper to convert amounts based on selected currency preference vs detected currency
  const convert = (amount: number) => {
    // If detected is MXN and user wants USD
    if (data.detectedCurrency.includes('MXN') && currency === Currency.USD) {
      return amount * EXCHANGE_RATE_MXN_TO_USD;
    }
    // If detected is USD and user wants MXN
    if (data.detectedCurrency.includes('USD') && currency === Currency.MXN) {
      return amount * EXCHANGE_RATE_USD_TO_MXN;
    }
    // Same currency or undefined detected, return as is (assuming 1:1 for display if unknown)
    return amount;
  };

  // 1. Normalize transactions: Apply currency conversion and strictly categorize negatives as Discounts
  const normalizedTransactions = useMemo(() => {
    return data.transactions.map(tx => {
      const convertedAmount = convert(tx.amount);
      // STRICT RULE: All negative amounts must constitute the Discount category
      // regardless of the original AI categorization.
      const category = convertedAmount < 0 ? Category.DISCOUNT : tx.category;

      return {
        ...tx,
        category, // Override category for consistency
        convertedAmount
      };
    });
  }, [data.transactions, currency]);

  // 2. Aggregate data for Charts based on normalized transactions
  const chartData = useMemo(() => {
    const agg: Record<string, number> = {};

    normalizedTransactions.forEach(tx => {
        // Aggregate actual signed values. Discounts will be negative.
        agg[tx.category] = (agg[tx.category] || 0) + tx.convertedAmount;
    });

    return Object.keys(agg).map(key => ({ 
      name: key, 
      value: agg[key],
      // For PieChart we need absolute values for slice sizing
      absValue: Math.abs(agg[key]) 
    }));
  }, [normalizedTransactions]);

  // 3. Filter transactions for the Table view
  const filteredTransactions = useMemo(() => {
    return normalizedTransactions.filter(tx => {
      const matchesSearch = tx.cleanName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.originalDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || tx.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [normalizedTransactions, searchTerm, categoryFilter]);

  const totalSpend = filteredTransactions.reduce((acc, curr) => acc + curr.convertedAmount, 0);

  // Clone and sort for BarChart - sort by absolute magnitude
  const topExpenses = useMemo(() => {
    return [...chartData].sort((a, b) => b.absValue - a.absValue).slice(0, 5);
  }, [chartData]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat(language === Language.ES ? 'es-MX' : 'en-US', {
      style: 'currency',
      currency: currency
    }).format(val);
  };

  const handleChartClick = (data: any) => {
