                        opacity={categoryFilter === 'All' || isSelected ? 1 : 0.3}
                      />
                    );
                  })}
                </Pie>
                {/* Tooltip displays the original signed value from payload */}
                <Tooltip formatter={(value: number, name: string, props: any) => formatCurrency(props.payload.value)} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2">Click segments to filter details</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col">
