          <div className="w-full h-64">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart 
                 data={topExpenses} 
                 layout="vertical"
                 cursor="pointer"
               >
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                  <Tooltip formatter={(value: number) => formatCurrency(value)} />
                  <Bar 
                    dataKey="value" // Use actual signed value (bars can go negative)
                    radius={[0, 4, 4, 0]} 
                    onClick={handleChartClick}
                  >
                     {topExpenses.map((entry, index) => {
                       const isDiscount = entry.name === Category.DISCOUNT;
                       const isSelected = categoryFilter === entry.name;
                       return (
                         <Cell 
                           key={`cell-${index}`} 
                           fill={CATEGORY_COLORS[entry.name] || DEFAULT_COLOR} 
                           stroke={isDiscount ? '#047857' : 'none'}
                           strokeWidth={isDiscount ? 2 : 0}
                           opacity={categoryFilter === 'All' || isSelected ? 1 : 0.3}
                         />
                       );
                     })}
                  </Bar>
               </BarChart>
             </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2 text-center">Click bars to filter details</p>
