                          color: badgeColor
                        }}
                      >
                        {tx.category.split('/')[language === Language.ES ? 0 : 1]}
                      </span>
                    </td>
                    <td className={`px-6 py-3 text-right font-medium ${tx.convertedAmount < 0 ? 'text-green-600' : 'text-gray-900'}`}>
                      {formatCurrency(tx.convertedAmount)}
