};

import React, { useMemo, useState } from 'react';
import { AnalysisResult, Currency, Language, Transaction, Category } from '../types';
import { TRANSLATIONS, EXCHANGE_RATE_MXN_TO_USD, EXCHANGE_RATE_USD_TO_MXN } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Search, ArrowUpDown, Filter, Calendar, Download } from 'lucide-react';

interface Props {
  data: AnalysisResult;
  language: Language;
  currency: Currency;
  onReset: () => void;
}

// Define specific colors for each category to ensure consistency across charts and table
// Colors chosen for accessibility and distinctness
const CATEGORY_COLORS: Record<string, string> = {
  [Category.FOOD_AND_BEVERAGE]: '#0D9488', // Teal (Combined Food & Drink)
  [Category.ROOM]: '#3B82F6',      // Blue (Primary)
  [Category.TAX]: '#EF4444',       // Red (Alert/Cost)
  [Category.SERVICE]: '#8B5CF6',   // Violet (Distinct)
  [Category.DISCOUNT]: '#F59E0B',  // Amber (Highlight/Savings)
  [Category.OTHER]: '#64748B',     // Slate (Neutral)
};

const DEFAULT_COLOR = '#9CA3AF'; // Gray (Fallback for unknown categories)

export const Dashboard: React.FC<Props> = ({ data, language, currency, onReset }) => {
  const t = TRANSLATIONS[language];
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('All');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  // Helper to convert amounts based on selected currency preference vs detected currency
  const convert = (amount: number) => {
    // If detected is MXN and user wants USD
    if (data.detectedCurrency.includes('MXN') && currency === Currency.USD) {
      return amount * EXCHANGE_RATE_MXN_TO_USD;
    }
    // If detected is USD and user wants MXN
    if (data.detectedCurrency.includes('USD') && currency === Currency.MXN) {
      return amount * EXCHANGE_RATE_USD_TO_MXN;
    }
    // Same currency or undefined detected, return as is (assuming 1:1 for display if unknown)
    return amount;
  };

  // 1. Normalize transactions
  const normalizedTransactions = useMemo(() => {
    return data.transactions.map(tx => {
      const convertedAmount = convert(tx.amount);
      return {
        ...tx,
        convertedAmount
      };
    });
  }, [data.transactions, currency]);

  // Helper to parse transaction date (DD/MM/YYYY)
  const parseTxDate = (dateStr: string) => {
    if (!dateStr) return null;
    const parts = dateStr.split('/');
    if (parts.length !== 3) return null;
    // Month is 0-indexed in JS Date
    return new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]));
  };

  // Helper to parse input date (YYYY-MM-DD)
  const parseInputDate = (dateStr: string) => {
    if (!dateStr) return null;
    const parts = dateStr.split('-');
    if (parts.length !== 3) return null;
    return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
  };

  // 2. Filter transactions for the Table view
  const filteredTransactions = useMemo(() => {
    const start = parseInputDate(startDate);
    const end = parseInputDate(endDate);

    return normalizedTransactions.filter(tx => {
      const matchesSearch = tx.cleanName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.originalDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || tx.category === categoryFilter;

      let matchesDate = true;
      if (start || end) {
        const txDate = parseTxDate(tx.date);
        if (txDate) {
          // Compare using timestamps of dates at 00:00:00
          if (start && txDate.getTime() < start.getTime()) {
            matchesDate = false;
          }
          if (end && txDate.getTime() > end.getTime()) {
            matchesDate = false;
          }
        }
      }

      return matchesSearch && matchesCategory && matchesDate;
    });
  }, [normalizedTransactions, searchTerm, categoryFilter, startDate, endDate]);

  const totalSpend = filteredTransactions.reduce((acc, curr) => acc + curr.convertedAmount, 0);

  // 3. Aggregate data for Charts
  // We use normalizedTransactions + Date Filter (ignoring Category filter)
  // This ensures the charts stay "full" even when a specific category is selected,
  // allowing the user to see the context of their selection.
  const chartData = useMemo(() => {
    const agg: Record<string, number> = {};

    const transactionsForCharts = normalizedTransactions.filter(tx => {
        const start = parseInputDate(startDate);
        const end = parseInputDate(endDate);
        let matchesDate = true;
        if (start || end) {
            const txDate = parseTxDate(tx.date);
            if (txDate) {
              if (start && txDate.getTime() < start.getTime()) matchesDate = false;
              if (end && txDate.getTime() > end.getTime()) matchesDate = false;
            }
        }
        return matchesDate;
    });

    transactionsForCharts.forEach(tx => {
        const amt = Math.abs(tx.convertedAmount);
        if (amt !== 0) {
            agg[tx.category] = (agg[tx.category] || 0) + amt;
        }
    });
    return Object.keys(agg).map(key => ({ name: key, value: agg[key] }));
  }, [normalizedTransactions, startDate, endDate]);

  // Clone and sort for BarChart
  const topExpenses = useMemo(() => {
    return [...chartData].sort((a, b) => b.value - a.value).slice(0, 5);
  }, [chartData]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat(language === Language.ES ? 'es-MX' : 'en-US', {
      style: 'currency',
      currency: currency
    }).format(val);
  };

  // --- INTERACTIVITY HANDLERS ---

  // Handle clicks on Chart Shapes (Slices/Bars) or Background
  const handleChartClick = (state: any) => {
    // 1. Check if user clicked a specific shape (Slice/Bar)
    if (state && state.activePayload && state.activePayload.length > 0) {
      const payload = state.activePayload[0].payload;
      if (payload && payload.name) {
        // Toggle selection
        setCategoryFilter(prev => prev === payload.name ? 'All' : payload.name);
        return;
      }
    }

    // 2. If no valid shape clicked (Background click), reset filter
    // Only reset if we are currently filtered to avoid unnecessary re-renders
    if (categoryFilter !== 'All') {
      setCategoryFilter('All');
    }
  };

  // Handle clicks on Legend Items
  const handleLegendClick = (data: any) => {
    // Recharts Legend 'value' prop usually contains the category name text
    if (data && data.value) {
      setCategoryFilter(prev => prev === data.value ? 'All' : data.value);
    }
  };

  const handleExportCSV = () => {
    // CSV Header
    const headers = [t.date, t.cleanName, t.description, t.category, t.amount, 'Currency'];

    // CSV Rows
    const rows = filteredTransactions.map(tx => [
      tx.date,
      `"${tx.cleanName.replace(/"/g, '""')}"`, // Escape quotes
      `"${tx.originalDescription.replace(/"/g, '""')}"`,
      tx.category,
      tx.convertedAmount.toFixed(2),
      currency
    ]);

    // Combine with BOM for Excel UTF-8 compatibility
    const csvContent = "\uFEFF" + [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    // Create Blob and Download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `${data.hotelName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_export.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="w-full max-w-6xl mx-auto space-y-6">

      {/* Header Info */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <div className="flex flex-col md:flex-row justify-between items-start mb-6 gap-4">
          <div className="flex-1">
             <h2 className="text-3xl font-bold text-gray-800">{data.hotelName}</h2>
             <div className="flex flex-wrap gap-2 mt-2">
               <button 
                 onClick={handleExportCSV}
                 className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-700 rounded-md text-sm font-medium hover:bg-blue-100 transition-colors"
               >
                 <Download size={16} />
                 {t.exportCSV}
               </button>
             </div>
          </div>
          <div className="text-right whitespace-nowrap">
            <p className="text-sm text-gray-500 uppercase tracking-wide">{t.totalSpend}</p>
            <p className="text-4xl font-extrabold text-blue-600">{formatCurrency(totalSpend)}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-5 rounded-lg border border-gray-100">
            <div className="space-y-3">
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.guest}</span>
                    <span className="text-gray-900 font-semibold">{data.guestName}</span>
                </div>
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.room}</span>
                    <span className="text-gray-900 font-semibold">{data.roomNumber}</span>
                </div>
                <div className="flex justify-between">
                    <span className="text-gray-500 font-medium">{t.folio}</span>
                    <span className="text-gray-900 font-semibold">{data.confirmationNumber}</span>
                </div>
            </div>
            <div className="space-y-3">
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.checkIn}</span>
                    <span className="text-gray-900 font-semibold">{data.checkIn}</span>
                </div>
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.checkOut}</span>
                    <span className="text-gray-900 font-semibold">{data.checkOut}</span>
                </div>
                <div className="flex justify-between">
                    <span className="text-gray-500 font-medium">{t.address}</span>
                    <span className="text-gray-900 font-semibold truncate max-w-[200px]" title={data.hotelAddress}>{data.hotelAddress}</span>
                </div>
            </div>
        </div>
      </div>

      {/* Charts Area */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Pie Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col items-center">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">{t.categoryDistribution}</h3>
          <div className="w-full h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart onClick={handleChartClick}>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                  cursor="pointer"
                >
                  {chartData.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={CATEGORY_COLORS[entry.name] || DEFAULT_COLOR} 
                      stroke={categoryFilter === entry.name ? '#000' : '#fff'}
                      strokeWidth={categoryFilter === entry.name ? 2 : 1}
                      opacity={categoryFilter === 'All' || categoryFilter === entry.name ? 1 : 0.4}
                      cursor="pointer"
                    />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
                <Legend onClick={handleLegendClick} wrapperStyle={{ cursor: 'pointer' }} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2">Click segments to filter details</p>
        </div>

        {/* Bar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">Top Expenses ( & Discounts )</h3>
          <div className="w-full h-64">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart 
                 data={topExpenses} 
                 layout="vertical"
                 onClick={handleChartClick}
               >
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                  <Tooltip formatter={(value: number) => formatCurrency(value)} />
                  <Bar 
                    dataKey="value" 
                    fill="#3b82f6" 
                    radius={[0, 4, 4, 0]}
                    cursor="pointer"
                  >
                     {topExpenses.map((entry, index) => (
                       <Cell 
                         key={`cell-${index}`} 
                         fill={CATEGORY_COLORS[entry.name] || DEFAULT_COLOR} 
                         stroke={categoryFilter === entry.name ? '#000' : '#fff'}
                         strokeWidth={categoryFilter === entry.name ? 2 : 1}
                         opacity={categoryFilter === 'All' || categoryFilter === entry.name ? 1 : 0.4}
                         cursor="pointer"
                       />
                     ))}
                  </Bar>
               </BarChart>
             </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2 text-center">Click bars to filter details</p>
        </div>
      </div>

      {/* Transactions Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-200 flex flex-col xl:flex-row gap-4 justify-between items-start xl:items-center bg-gray-50">

          <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full xl:w-auto">
             <div className="flex items-center gap-2">
                <h3 className="text-lg font-semibold whitespace-nowrap">{t.transactions}</h3>
                {categoryFilter !== 'All' && (
                  <span 
                    className="text-xs px-2 py-1 rounded-full flex items-center gap-1 font-medium border"
                    style={{ 
                      backgroundColor: `${CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR}20`, 
                      color: CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR,
                      borderColor: `${CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR}40`
                    }}
                  >
                    {categoryFilter.split('/')[language === Language.ES ? 0 : 1]}
                    <button onClick={() => setCategoryFilter('All')} className="font-bold ml-1 hover:opacity-75">×</button>
                  </span>
                )}
             </div>

             {/* Date Range Inputs */}
             <div className="flex items-center gap-2 bg-white px-2 py-1.5 rounded-lg border border-gray-300 shadow-sm w-full sm:w-auto">
                <Calendar size={16} className="text-gray-400" />
                <div className="flex items-center gap-1">
                   <div className="relative">
                      <input 
                        type="date" 
                        className="text-xs border-none focus:ring-0 p-0 text-gray-600 w-[100px] outline-none"
                        value={startDate}
                        onChange={(e) => setStartDate(e.target.value)}
                        placeholder={t.startDate}
                        title={t.startDate}
                      />
                   </div>
                   <span className="text-gray-400">-</span>
                   <div className="relative">
                      <input 
                        type="date" 
                        className="text-xs border-none focus:ring-0 p-0 text-gray-600 w-[100px] outline-none"
                        value={endDate}
                        onChange={(e) => setEndDate(e.target.value)}
                        placeholder={t.endDate}
                        title={t.endDate}
                      />
                   </div>
                </div>
                {(startDate || endDate) && (
                   <button 
                     onClick={() => { setStartDate(''); setEndDate(''); }} 
                     className="text-gray-400 hover:text-gray-600 ml-1"
                   >
                     ×
                   </button>
                )}
             </div>
          </div>

          <div className="flex gap-2 w-full xl:w-auto flex-wrap sm:flex-nowrap">
            <div className="relative flex-1 sm:min-w-[200px]">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
              <input 
                type="text" 
                placeholder="Search..." 
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="relative">
               <select 
                  className="pl-3 pr-8 py-2 border border-gray-300 rounded-lg text-sm bg-white appearance-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer w-full sm:w-auto"
                  value={categoryFilter}
                  onChange={(e) => setCategoryFilter(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {Object.values(Category).map(cat => (
                   <option key={cat} value={cat}>{cat}</option>
                 ))}
               </select>
               <Filter className="absolute right-2 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" size={14} />
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
              <tr>
                <th className="px-6 py-3">{t.date}</th>
                <th className="px-6 py-3">{t.cleanName}</th>
                <th className="px-6 py-3 hidden md:table-cell">{t.description}</th>
                <th className="px-6 py-3">{t.category}</th>
                <th className="px-6 py-3 text-right">{t.amount}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredTransactions.map((tx, idx) => {
                const badgeColor = CATEGORY_COLORS[tx.category] || DEFAULT_COLOR;

                return (
                  <tr key={idx} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-3 whitespace-nowrap text-gray-500">{tx.date}</td>
                    <td className="px-6 py-3 font-medium text-gray-900">{tx.cleanName}</td>
                    <td className="px-6 py-3 text-gray-400 text-xs hidden md:table-cell truncate max-w-xs">{tx.originalDescription}</td>
                    <td className="px-6 py-3">
                      <span 
                        className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium"
                        style={{ 
                          backgroundColor: `${badgeColor}20`, // 20 hex opacity = ~12% opacity
                          color: badgeColor
                        }}
                      >
                        {tx.category.split('/')[language === Language.ES ? 0 : 1]}
                      </span>
                    </td>
                    <td 
                      className="px-6 py-3 text-right font-bold"
                      style={{ color: badgeColor }}
                    >
                      {formatCurrency(tx.convertedAmount)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filteredTransactions.length === 0 && (
            <div className="p-8 text-center text-gray-500">
              No transactions found matching your filters.
            </div>
          )}
        </div>
      </div>

      <div className="flex justify-center pt-6 pb-12">
        <button 
          onClick={onReset}
          className="text-gray-500 hover:text-gray-800 underline text-sm transition-colors"
        >
          {t.reset}
        </button>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, Category } from "../types";

const parsePdf = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      // Remove Data-URL declaration (e.g., data:application/pdf;base64,)
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const analyzeStatement = async (file: File): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is missing.");
  }

  const base64Data = await parsePdf(file);
  const ai = new GoogleGenAI({ apiKey });

  // Define the schema for structured output
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      hotelName: { type: Type.STRING, description: "Name of the hotel found in the header" },
      hotelAddress: { type: Type.STRING, description: "Address of the hotel" },
      guestName: { type: Type.STRING, description: "Name of the guest" },
      roomNumber: { type: Type.STRING, description: "Room number" },
      checkIn: { type: Type.STRING, description: "Arrival date (DD/MM/YYYY)" },
      checkOut: { type: Type.STRING, description: "Departure date (DD/MM/YYYY)" },
      confirmationNumber: { type: Type.STRING, description: "Folio or confirmation number" },
      detectedCurrency: { type: Type.STRING, description: "Currency symbol or code detected (MXN, USD, $)" },
      transactions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            date: { type: Type.STRING },
            originalDescription: { type: Type.STRING },
            cleanName: { 
              type: Type.STRING, 
              description: "Simplified commercial name. Remove dates, transaction codes, room numbers. E.g., 'REST EL PATIO 23423' -> 'El Patio'" 
            },
            amount: { type: Type.NUMBER },
            category: { 
              type: Type.STRING, 
              enum: Object.values(Category),
              description: "Categorize based on description. 'Dersan' or 'ISH' are Impuestos/Tax." 
            },
            currency: { type: Type.STRING }
          },
          required: ["date", "originalDescription", "cleanName", "amount", "category"]
        }
      },
      totalAmount: { type: Type.NUMBER }
    },
    required: ["hotelName", "guestName", "transactions", "totalAmount"]
  };

  const systemInstruction = `
    You are an expert financial analyst for hotel operations.
    Your task is to extract transaction data and header details from a hotel account statement PDF with perfect accuracy.

    CRITICAL RULES:
    1. Header Information: Extract Hotel Name, Address, Guest Name, Room Number, Folio/Confirmation number accurately from the top of the document. For dates like Check-In and Check-Out, convert formats like '19-01-26' to a standard 'DD/MM/YYYY' format (e.g., '19/01/2026').
    2. Transactions: Extract the Date, Description, and Amount for each line item in the main table.
    3. 'cleanName': From the original description, create a simplified commercial name. Remove dates, transaction codes, room numbers, and any other non-essential text. For example, 'REST EL PATIO 23423' should become 'El Patio'.
    4. 'category': Categorize strictly into:
       - Alimentos y Bebidas/Food & Beverage (Restaurants, Breakfast, Dinner, Bar, Lobby Bar, Minibar, Room Service Food)
       - Habitación/Room (Room charge, Upgrades, Early check-in)
       - Impuestos/Tax (Look specifically for 'Dersan', 'ISH', 'IVA', 'TUA', or generic tax descriptions)
       - Descuento/Discount (Any negative values, credits, or items labeled 'Abonos')
       - Servicio/Service (Tips, Laundry, Spa, Telephone, Transport, Valet Parking)
       - Otros/Other (Any other charge)
    5. Amounts: Handle negative numbers correctly for the 'amount' field. Credits and discounts must be negative.
    6. Currency: Accurately detect the currency of the document (e.g., MXN, USD).
    7. Total Amount: This is the most important field. Find the final total printed on the statement (e.g., 'Total MxN', 'Total Charges'). Use this value for the 'totalAmount' field. THIS IS THE SOURCE OF TRUTH AND IS MORE ACCURATE THAN MANUALLY SUMMING THE TRANSACTION LINES. For example, if the document shows 'Total MxN 25,224.10', you must use 25224.10.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: file.type,
              data: base64Data
            }
          },
          {
            text: "Analyze this hotel statement PDF and extract the data according to the JSON schema."
          }
        ]
      },
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response from AI");
    }

    const result = JSON.parse(text) as AnalysisResult;

    // Data validation and correction: Ensure the dashboard total matches the extracted PDF total.
    // The dashboard recalculates spend, so we pass the authoritative total from the PDF.
    // If the model's summed transactions don't match its extracted total, this ensures the UI is still correct.
    const transactionSum = result.transactions.reduce((sum, tx) => sum + tx.amount, 0);
    if (Math.abs(transactionSum - result.totalAmount) > 1) { // Allow for small rounding diffs
        console.warn(`Sum of transactions (${transactionSum}) does not match the extracted total amount (${result.totalAmount}). The extracted total will be used.`);
    }

    return result;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useMemo, useState } from 'react';
import { AnalysisResult, Currency, Language, Transaction, Category } from '../types';
import { TRANSLATIONS, EXCHANGE_RATE_MXN_TO_USD, EXCHANGE_RATE_USD_TO_MXN } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Search, ArrowUpDown, Filter, Calendar, Download } from 'lucide-react';

interface Props {
  data: AnalysisResult;
  language: Language;
  currency: Currency;
  onReset: () => void;
}

// Define specific colors for each category to ensure consistency across charts and table
// Colors chosen for accessibility and distinctness
const CATEGORY_COLORS: Record<string, string> = {
  [Category.FOOD_AND_BEVERAGE]: '#0D9488', // Teal (Combined Food & Drink)
  [Category.ROOM]: '#3B82F6',      // Blue (Primary)
  [Category.TAX]: '#EF4444',       // Red (Alert/Cost)
  [Category.SERVICE]: '#8B5CF6',   // Violet (Distinct)
  [Category.DISCOUNT]: '#F59E0B',  // Amber (Highlight/Savings)
  [Category.OTHER]: '#64748B',     // Slate (Neutral)
};

const DEFAULT_COLOR = '#9CA3AF'; // Gray (Fallback for unknown categories)

export const Dashboard: React.FC<Props> = ({ data, language, currency, onReset }) => {
  const t = TRANSLATIONS[language];
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState<string>('All');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  // Helper to convert amounts based on selected currency preference vs detected currency
  const convert = (amount: number) => {
    // If detected is MXN and user wants USD
    if (data.detectedCurrency.includes('MXN') && currency === Currency.USD) {
      return amount * EXCHANGE_RATE_MXN_TO_USD;
    }
    // If detected is USD and user wants MXN
    if (data.detectedCurrency.includes('USD') && currency === Currency.MXN) {
      return amount * EXCHANGE_RATE_USD_TO_MXN;
    }
    // Same currency or undefined detected, return as is (assuming 1:1 for display if unknown)
    return amount;
  };

  // 1. Normalize transactions
  const normalizedTransactions = useMemo(() => {
    return data.transactions.map(tx => {
      const convertedAmount = convert(tx.amount);
      return {
        ...tx,
        convertedAmount
      };
    });
  }, [data.transactions, currency]);

  // Helper to parse transaction date (DD/MM/YYYY)
  const parseTxDate = (dateStr: string) => {
    if (!dateStr) return null;
    const parts = dateStr.split('/');
    if (parts.length !== 3) return null;
    // Month is 0-indexed in JS Date
    return new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]));
  };

  // Helper to parse input date (YYYY-MM-DD)
  const parseInputDate = (dateStr: string) => {
    if (!dateStr) return null;
    const parts = dateStr.split('-');
    if (parts.length !== 3) return null;
    return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
  };

  // 2. Filter transactions for the Table view
  const filteredTransactions = useMemo(() => {
    const start = parseInputDate(startDate);
    const end = parseInputDate(endDate);

    return normalizedTransactions.filter(tx => {
      const matchesSearch = tx.cleanName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            tx.originalDescription.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || tx.category === categoryFilter;

      let matchesDate = true;
      if (start || end) {
        const txDate = parseTxDate(tx.date);
        if (txDate) {
          // Compare using timestamps of dates at 00:00:00
          if (start && txDate.getTime() < start.getTime()) {
            matchesDate = false;
          }
          if (end && txDate.getTime() > end.getTime()) {
            matchesDate = false;
          }
        }
      }

      return matchesSearch && matchesCategory && matchesDate;
    });
  }, [normalizedTransactions, searchTerm, categoryFilter, startDate, endDate]);

  const totalSpend = convert(data.totalAmount);

  // 3. Aggregate data for Charts. This data should only be affected by the date range,
  // not by the category or search filters, so the charts provide a stable overview.
  const chartData = useMemo(() => {
    const start = parseInputDate(startDate);
    const end = parseInputDate(endDate);

    const transactionsForCharts = normalizedTransactions.filter(tx => {
      let matchesDate = true;
      if (start || end) {
        const txDate = parseTxDate(tx.date);
        if (txDate) {
          if (start && txDate.getTime() < start.getTime()) {
            matchesDate = false;
          }
          if (end && txDate.getTime() > end.getTime()) {
            matchesDate = false;
          }
        } else {
          matchesDate = !start && !end;
        }
      }
      return matchesDate;
    });

    const agg: Record<string, number> = {};
    transactionsForCharts.forEach(tx => {
        const amt = Math.abs(tx.convertedAmount);
        if (amt !== 0) {
            agg[tx.category] = (agg[tx.category] || 0) + amt;
        }
    });
    return Object.keys(agg).map(key => ({ name: key, value: agg[key] }));
  }, [normalizedTransactions, startDate, endDate]);

  // Clone and sort for BarChart
  const topExpenses = useMemo(() => {
    return [...chartData].sort((a, b) => b.value - a.value).slice(0, 5);
  }, [chartData]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat(language === Language.ES ? 'es-MX' : 'en-US', {
      style: 'currency',
      currency: currency
    }).format(val);
  };

  // Enhanced Chart Click Handler
  const handleChartClick = (state: any) => {
    // If activePayload is present, user clicked on a slice/bar
    if (state && state.activePayload && state.activePayload.length > 0) {
      const payload = state.activePayload[0].payload;
      if (payload && payload.name) {
        // Toggle: if clicking the same category, reset to All
        setCategoryFilter(prev => prev === payload.name ? 'All' : payload.name);
        return;
      }
    }

    // If no activePayload (background click), reset filter
    if (categoryFilter !== 'All') {
      setCategoryFilter('All');
    }
  };

  const handleExportCSV = () => {
    // CSV Header
    const headers = [t.date, t.cleanName, t.description, t.category, t.amount, 'Currency'];

    // CSV Rows
    const rows = filteredTransactions.map(tx => [
      tx.date,
      `"${tx.cleanName.replace(/"/g, '""')}"`, // Escape quotes
      `"${tx.originalDescription.replace(/"/g, '""')}"`,
      tx.category,
      tx.convertedAmount.toFixed(2),
      currency
    ]);

    // Combine with BOM for Excel UTF-8 compatibility
    const csvContent = "\uFEFF" + [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    // Create Blob and Download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `${data.hotelName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_export.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="w-full max-w-6xl mx-auto space-y-6">

      {/* Header Info - Updated Layout */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <div className="flex flex-col md:flex-row justify-between items-start mb-6 gap-4">
          <div className="flex-1">
             <h2 className="text-3xl font-bold text-gray-800">{data.hotelName}</h2>
             <div className="flex flex-wrap gap-2 mt-2">
               <button 
                 onClick={handleExportCSV}
                 className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-700 rounded-md text-sm font-medium hover:bg-blue-100 transition-colors"
               >
                 <Download size={16} />
                 {t.exportCSV}
               </button>
             </div>
          </div>
          <div className="text-right whitespace-nowrap">
            <p className="text-sm text-gray-500 uppercase tracking-wide">{t.totalSpend}</p>
            <p className="text-4xl font-extrabold text-blue-600">{formatCurrency(totalSpend)}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-gray-50 p-5 rounded-lg border border-gray-100">
            <div className="space-y-3">
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.guest}</span>
                    <span className="text-gray-900 font-semibold">{data.guestName}</span>
                </div>
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.room}</span>
                    <span className="text-gray-900 font-semibold">{data.roomNumber}</span>
                </div>
                <div className="flex justify-between">
                    <span className="text-gray-500 font-medium">{t.folio}</span>
                    <span className="text-gray-900 font-semibold">{data.confirmationNumber}</span>
                </div>
            </div>
            <div className="space-y-3">
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.checkIn}</span>
                    <span className="text-gray-900 font-semibold">{data.checkIn}</span>
                </div>
                <div className="flex justify-between border-b border-gray-200 pb-2">
                    <span className="text-gray-500 font-medium">{t.checkOut}</span>
                    <span className="text-gray-900 font-semibold">{data.checkOut}</span>
                </div>
                <div className="flex justify-between">
                    <span className="text-gray-500 font-medium">{t.address}</span>
                    <span className="text-gray-900 font-semibold truncate max-w-[200px]" title={data.hotelAddress}>{data.hotelAddress}</span>
                </div>
            </div>
        </div>
      </div>

      {/* Charts Area */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col items-center">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">{t.categoryDistribution}</h3>
          <div className="w-full h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={chartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                  cursor="pointer"
                  onClick={(data, index, e) => handleChartClick({ activePayload: [{ payload: data }]})}
                >
                  {chartData.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={CATEGORY_COLORS[entry.name] || DEFAULT_COLOR} 
                      stroke={categoryFilter === entry.name ? '#000' : 'none'}
                      strokeWidth={2}
                      opacity={categoryFilter === 'All' || categoryFilter === entry.name ? 1 : 0.3}
                    />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2">Click segments to filter details</p>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 w-full text-left">Top Expenses ( & Discounts )</h3>
          <div className="w-full h-64">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart 
                 data={topExpenses} 
                 layout="vertical"
                 onClick={handleChartClick}
               >
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                  <Tooltip formatter={(value: number) => formatCurrency(value)} />
                  <Bar 
                    dataKey="value" 
                    fill="#3b82f6" 
                    radius={[0, 4, 4, 0]}
                    cursor="pointer"
                  >
                     {topExpenses.map((entry, index) => (
                       <Cell 
                         key={`cell-${index}`} 
                         fill={CATEGORY_COLORS[entry.name] || DEFAULT_COLOR} 
                         stroke={categoryFilter === entry.name ? '#000' : 'none'}
                         strokeWidth={2}
                         opacity={categoryFilter === 'All' || categoryFilter === entry.name ? 1 : 0.3}
                       />
                     ))}
                  </Bar>
               </BarChart>
             </ResponsiveContainer>
          </div>
          <p className="text-xs text-gray-400 mt-2 text-center">Click bars to filter details</p>
        </div>
      </div>

      {/* Transactions Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-200 flex flex-col xl:flex-row gap-4 justify-between items-start xl:items-center bg-gray-50">

          <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full xl:w-auto">
             <div className="flex items-center gap-2">
                <h3 className="text-lg font-semibold whitespace-nowrap">{t.transactions}</h3>
                {categoryFilter !== 'All' && (
                  <span 
                    className="text-xs px-2 py-1 rounded-full flex items-center gap-1 font-medium border"
                    style={{ 
                      backgroundColor: `${CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR}20`, 
                      color: CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR,
                      borderColor: `${CATEGORY_COLORS[categoryFilter] || DEFAULT_COLOR}40`
                    }}
                  >
                    {categoryFilter.split('/')[language === Language.ES ? 0 : 1]}
                    <button onClick={() => setCategoryFilter('All')} className="font-bold ml-1 hover:opacity-75">×</button>
                  </span>
                )}
             </div>

             {/* Date Range Inputs */}
             <div className="flex items-center gap-2 bg-white px-2 py-1.5 rounded-lg border border-gray-300 shadow-sm w-full sm:w-auto">
                <Calendar size={16} className="text-gray-400" />
                <div className="flex items-center gap-1">
                   <div className="relative">
                      <input 
                        type="date" 
                        className="text-xs border-none focus:ring-0 p-0 text-gray-600 w-[100px] outline-none"
                        value={startDate}
                        onChange={(e) => setStartDate(e.target.value)}
                        placeholder={t.startDate}
                        title={t.startDate}
                      />
                   </div>
                   <span className="text-gray-400">-</span>
                   <div className="relative">
                      <input 
                        type="date" 
                        className="text-xs border-none focus:ring-0 p-0 text-gray-600 w-[100px] outline-none"
                        value={endDate}
                        onChange={(e) => setEndDate(e.target.value)}
                        placeholder={t.endDate}
                        title={t.endDate}
                      />
                   </div>
                </div>
                {(startDate || endDate) && (
                   <button 
                     onClick={() => { setStartDate(''); setEndDate(''); }} 
                     className="text-gray-400 hover:text-gray-600 ml-1"
                   >
                     ×
                   </button>
                )}
             </div>
          </div>

          <div className="flex gap-2 w-full xl:w-auto flex-wrap sm:flex-nowrap">
            <div className="relative flex-1 sm:min-w-[200px]">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={16} />
              <input 
                type="text" 
                placeholder="Search..." 
                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="relative">
               <select 
                  className="pl-3 pr-8 py-2 border border-gray-300 rounded-lg text-sm bg-white appearance-none focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer w-full sm:w-auto"
                  value={categoryFilter}
                  onChange={(e) => setCategoryFilter(e.target.value)}
               >
                 <option value="All">All Categories</option>
                 {Object.values(Category).map(cat => (
                   <option key={cat} value={cat}>{cat}</option>
                 ))}
               </select>
               <Filter className="absolute right-2 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" size={14} />
            </div>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
              <tr>
